import sys

# Read number of test cases
t = int(sys.stdin.readline().strip())

# Process each sentence
for _ in range(t):
    line = sys.stdin.readline().strip().split('|')[0]  # Ignore anything after '|
    parts = line.split()  # Split the sentence into parts
    name = parts[0]  # The name is the first part
    if 'has' in parts:
        N = int(parts[2])  # Number of apples or marbles
        M = int(parts[6])  # Number bought or given
        print(N + M)  # Output the total
    elif 'had' in parts:
        N = int(parts[2])  # Number of candies
        M = int(parts[6])  # Number given away
        if M <= N:
            print(N - M)  # Output remaining candies
        else:
            print('INVALID')  # Invalid case
    elif 'gives' in parts:
        N = int(parts[2])  # Number of marbles
        M = int(parts[6])  # Number given away
        if M <= N:
            print(N - M)  # Output remaining marbles
